#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int maxPathSum(vector<vector<int>>& tree) {
        int n = tree.size();
        vector<int> values(n);
        for (int i = 0; i < n; i++) values[i] = tree[i][0];
        dfs(tree, values, 0);
        int res = INT_MIN;
        for (int val : values) res = max(res, val);
        return res;
    }
private:
    int dfs(vector<vector<int>>& tree, vector<int>& values, int node) {
        if (node == -1) return 0;
        int left = max(dfs(tree, values, tree[node][1]), 0);
        int right = max(dfs(tree, values, tree[node][2]), 0);
        values[node] += left + right;
        return values[node];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<vector<int>> tree(n, vector<int>(3));
    for (int i = 0; i < n; i++) cin >> tree[i][0] >> tree[i][1] >> tree[i][2];
    Solution sol;
    int ans = sol.maxPathSum(tree);
    cout << ans << '\n';
    return 0;
}
